if (!defined('CLI_SCRIPT')) { define('CLI_SCRIPT', true); }
require('/www/moodle/config.php');
require_once($CFG->dirroot . '/course/lib.php');
try {
    $course = $DB->get_record('course', ['shortname' => 'ZOOMDEMO01'], '*', MUST_EXIST);
    $module = $DB->get_record('modules', ['name' => 'zoom'], '*', MUST_EXIST);
    $admin = get_admin();
    \core\session\manager::set_user($admin);
    $now = time();
    $zoom = (object)[
        'course'        => $course->id,
        'name'          => 'Sample Zoom meeting (stub)',
        'intro'         => '<p>This is a <strong>stub</strong> Zoom activity created directly in the database so you can preview <code>mod_zoom</code>\'s UI inside Moodle Playground.</p><p>The Zoom REST API is not reachable from the sandbox, so the Join / Start buttons will not work — open the activity to inspect the view page layout, or edit it to inspect the mod_form.</p>',
        'introformat'   => FORMAT_HTML,
        'grade'         => 100,
        'meeting_id'    => 1234567890,
        'host_id'       => 'PLAYGROUND_DEMO_HOST',
        'created_at'    => gmdate('Y-m-d\\TH:i:s\\Z', $now),
        'start_time'    => $now + 3600,
        'duration'      => 3600,
        'timezone'      => 'Europe/Madrid',
        'webinar'       => 0,
        'recurring'     => 0,
        'timemodified'  => $now,
        'exists_on_zoom'=> 0,
    ];
    $zoomid = $DB->insert_record('zoom', $zoom);
    $cm = (object)[
        'course'       => $course->id,
        'module'       => $module->id,
        'instance'     => $zoomid,
        'section'      => 1,
        'idnumber'     => '',
        'added'        => $now,
        'score'        => 0,
        'indent'       => 0,
        'visible'      => 1,
        'visibleold'   => 1,
        'groupmode'    => 0,
        'groupingid'   => 0,
        'completion'   => 0,
        'showdescription' => 0,
    ];
    $cmid = add_course_module($cm);
    $DB->set_field('course_modules', 'instance', $zoomid, ['id' => $cmid]);
    course_add_cm_to_section($course->id, $cmid, 1);
    rebuild_course_cache($course->id, true);
    echo "Created mod_zoom instance id={$zoomid} cmid={$cmid} in course {$course->shortname}\n";
} catch (\Throwable $e) {
    echo 'ERROR: ' . $e->getMessage() . "\n";
}
